toolArgs.file_text:
@using sv_be4adc32477b413bb4c06541b0b48a40

<div class="catalog-filters">
    <h5>Filters</h5>

    <div class="filter-section">
        <h6>Categories</h6>
        @if (Categories.Count == 0)
        {
            <p class="text-muted small">No categories available</p>
        }
        else
        {
            @foreach (var category in Categories)
            {
                <div class="form-check">
                    <input class="form-check-input"
                           type="checkbox"
                           id="@($"cat-{category}")"
                           checked="@(selectedCategories.Contains(category))"
                           @onchange="@(e => ToggleCategory(category, (bool)(e.Value ?? false)))" />
                    <label class="form-check-label" for="@($"cat-{category}")">@category</label>
                </div>
            }
        }
    </div>

    <div class="filter-section">
        <h6>Price Range</h6>
        <div class="mb-2">
            <label class="form-label small" for="min-price">Min Price</label>
            <input id="min-price" type="number" class="form-control form-control-sm"
                   placeholder="Min" min="0" step="0.01"
                   value="@minPrice" @onchange="@(e => minPrice = ParseDecimal(e.Value))" />
        </div>
        <div class="mb-2">
            <label class="form-label small" for="max-price">Max Price</label>
            <input id="max-price" type="number" class="form-control form-control-sm"
                   placeholder="Max" min="0" step="0.01"
                   value="@maxPrice" @onchange="@(e => maxPrice = ParseDecimal(e.Value))" />
        </div>
    </div>

    <div class="filter-section">
        <div class="form-check">
            <input class="form-check-input" type="checkbox" id="in-stock-only"
                   checked="@inStockOnly" @onchange="@(e => inStockOnly = (bool)(e.Value ?? false))" />
            <label class="form-check-label" for="in-stock-only">In Stock Only</label>
        </div>
    </div>

    <div class="filter-actions">
        <button class="btn btn-primary btn-sm w-100 mb-2" @onclick="ApplyFilters">Apply Filters</button>
        <button class="btn btn-outline-secondary btn-sm w-100" @onclick="ClearFilters">Clear Filters</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public List<string> Categories { get; set; } = [];

    [Parameter]
    public ProductFilter? Filter { get; set; }

    [Parameter]
    public EventCallback<ProductFilter> OnApplyFilters { get; set; }

    [Parameter]
    public EventCallback OnClearFilters { get; set; }

    private HashSet<string> selectedCategories = new();
    private decimal? minPrice;
    private decimal? maxPrice;
    private bool inStockOnly;

    protected override void OnParametersSet()
    {
        if (Filter is not null)
        {
            selectedCategories = Filter.Categories is not null
                ? new HashSet<string>(Filter.Categories)
                : new HashSet<string>();
            minPrice = Filter.MinPrice;
            maxPrice = Filter.MaxPrice;
            inStockOnly = Filter.InStockOnly;
        }
    }

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
            selectedCategories.Add(category);
        else
            selectedCategories.Remove(category);
    }

    private async Task ApplyFilters()
    {
        var filter = new ProductFilter(
            Categories: selectedCategories.Count > 0 ? selectedCategories.ToList() : null,
            MinPrice: minPrice,
            MaxPrice: maxPrice,
            InStockOnly: inStockOnly
        );
        await OnApplyFilters.InvokeAsync(filter);
    }

    private async Task ClearFilters()
    {
        selectedCategories.Clear();
        minPrice = null;
        maxPrice = null;
        inStockOnly = false;
        await OnClearFilters.InvokeAsync();
    }

    private static decimal? ParseDecimal(object? value)
    {
        if (value is null || string.IsNullOrWhiteSpace(value.ToString()))
            return null;
        return decimal.TryParse(value.ToString(), out var result) ? result : null;
    }
}

