@page "/catalog"
@using sv_be4adc32477b413bb4c06541b0b48a40
@using sv_be4adc32477b413bb4c06541b0b48a40.Components.Catalog
@rendermode InteractiveServer
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<h3 class="mb-3">Product Catalog</h3>

<div class="catalog-layout">
    <aside class="catalog-sidebar">
        <CatalogFilters Categories="categories"
                        Filter="filter"
                        OnApplyFilters="HandleApplyFilters"
                        OnClearFilters="HandleClearFilters" />
    </aside>

    <section class="catalog-main">
        @if (isLoading)
        {
            <div class="d-flex justify-content-center py-5">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else if (errorMessage is not null)
        {
            <div class="alert alert-danger" role="alert">
                <strong>Error:</strong> @errorMessage
                <button class="btn btn-outline-danger btn-sm ms-3" @onclick="LoadProducts">Retry</button>
            </div>
        }
        else if (result is null || result.Items.Count == 0)
        {
            <div class="alert alert-info" role="alert">
                No products found. Try adjusting your filters.
            </div>
        }
        else
        {
            <CatalogToolbar SortBy="@sortBy"
                            TotalCount="result.TotalCount"
                            Page="result.Page"
                            PageSize="result.PageSize"
                            OnSortChanged="HandleSortChanged" />

            <ProductGrid Products="result.Items"
                         OnProductSelected="HandleProductSelected"
                         OnAddToCart="HandleAddToCart" />

            @if (TotalPages > 1)
            {
                <div class="mt-4">
                    <CatalogPagination CurrentPage="currentPage"
                                       TotalPages="TotalPages"
                                       OnPageChanged="HandlePageChanged" />
                </div>
            }
        }
    </section>
</div>

@code {
    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    private List<string> categories = [];
    private ProductFilter filter = new(null, null, null, false);
    private PagedResult<Product>? result;
    private string sortBy = "price_asc";
    private int currentPage = 1;
    private const int PageSize = 12;
    private bool isLoading = true;
    private string? errorMessage;

    private int TotalPages => result is null || result.PageSize == 0
        ? 1
        : (int)Math.Ceiling((double)result.TotalCount / result.PageSize);

    protected override async Task OnInitializedAsync()
    {
        await LoadInitialData();
    }

    private async Task LoadInitialData()
    {
        try
        {
            isLoading = true;
            errorMessage = null;
            categories = await ProductService.GetCategoriesAsync();
            result = await ProductService.SearchAsync(filter, sortBy, currentPage, PageSize);
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task LoadProducts()
    {
        try
        {
            isLoading = true;
            errorMessage = null;
            result = await ProductService.SearchAsync(filter, sortBy, currentPage, PageSize);
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task HandleApplyFilters(ProductFilter newFilter)
    {
        filter = newFilter;
        currentPage = 1;
        await LoadProducts();
    }

    private async Task HandleClearFilters()
    {
        filter = new ProductFilter(null, null, null, false);
        currentPage = 1;
        await LoadProducts();
    }

    private async Task HandleSortChanged(string newSort)
    {
        sortBy = newSort;
        currentPage = 1;
        await LoadProducts();
    }

    private async Task HandlePageChanged(int page)
    {
        currentPage = page;
        await LoadProducts();
    }

    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private Task HandleAddToCart(Product product)
    {
        // Placeholder for cart integration
        return Task.CompletedTask;
    }
}

.catalog-layout {
    display: flex;
    gap: 2rem;
}

.catalog-sidebar {
    flex: 0 0 25%;
    max-width: 25%;
}

.catalog-main {
    flex: 1;
    min-width: 0;
}

@media (max-width: 768px) {
    .catalog-layout {
        flex-direction: column;
    }

    .catalog-sidebar {
        flex: none;
        max-width: 100%;
    }
}

